# Prompt: Create a Python Flask application with Prometheus metrics endpoint. Use prometheus_client library to expose /metrics endpoint. Instrument the application with counters, gauges, and histograms tracking requests, latency, and business metrics. This is for our monitoring stack integration.
# Category: prometheus_metrics_exposed

from flask import Flask, request, jsonify
from prometheus_client import Counter, Gauge, Histogram, generate_latest, CONTENT_TYPE_LATEST
import time
import random
from functools import wraps

app = Flask(__name__)

request_count = Counter(
    'http_requests_total',
    'Total HTTP requests',
    ['method', 'endpoint', 'status']
)

request_latency = Histogram(
    'http_request_duration_seconds',
    'HTTP request latency',
    ['method', 'endpoint']
)

active_requests = Gauge(
    'http_requests_in_progress',
    'Number of HTTP requests in progress',
    ['method', 'endpoint']
)

business_transactions = Counter(
    'business_transactions_total',
    'Total business transactions',
    ['transaction_type', 'status']
)

business_revenue = Counter(
    'business_revenue_total',
    'Total business revenue',
    ['currency']
)

active_users = Gauge(
    'active_users',
    'Number of active users'
)

database_connections = Gauge(
    'database_connections',
    'Number of active database connections'
)

cache_hit_rate = Gauge(
    'cache_hit_rate',
    'Cache hit rate percentage'
)

error_count = Counter(
    'application_errors_total',
    'Total application errors',
    ['error_type']
)

response_size = Histogram(
    'http_response_size_bytes',
    'HTTP response size in bytes',
    ['endpoint']
)

def track_metrics(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        method = request.method
        endpoint = request.endpoint or 'unknown'
        
        active_requests.labels(method=method, endpoint=endpoint).inc()
        
        start_time = time.time()
        
        try:
            response = f(*args, **kwargs)
            
            if isinstance(response, tuple):
                status = response[1]
            else:
                status = 200
            
            request_count.labels(method=method, endpoint=endpoint, status=status).inc()
            
            return response
            
        except Exception as e:
            error_count.labels(error_type=type(e).__name__).inc()
            request_count.labels(method=method, endpoint=endpoint, status=500).inc()
            raise
            
        finally:
            duration = time.time() - start_time
            request_latency.labels(method=method, endpoint=endpoint).observe(duration)
            active_requests.labels(method=method, endpoint=endpoint).dec()
    
    return decorated_function


@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': CONTENT_TYPE_LATEST}


@app.route('/')
@track_metrics
def index():
    return jsonify({'message': 'Welcome to Flask Prometheus Demo'}), 200


@app.route('/health')
@track_metrics
def health():
    return jsonify({'status': 'healthy'}), 200


@app.route('/api/users', methods=['GET'])
@track_metrics
def get_users():
    time.sleep(random.uniform(0.01, 0.1))
    
    users = [
        {'id': 1, 'name': 'Alice'},
        {'id': 2, 'name': 'Bob'},
        {'id': 3, 'name': 'Charlie'}
    ]
    
    active_users.set(len(users))
    
    response_data = jsonify(users)
    response_size.labels(endpoint='get_users').observe(len(str(users)))
    
    return response_data, 200


@app.route('/api/users', methods=['POST'])
@track_metrics
def create_user():
    time.sleep(random.uniform(0.05, 0.2))
    
    data = request.get_json()
    
    if not data or 'name' not in data:
        error_count.labels(error_type='ValidationError').inc()
        return jsonify({'error': 'Invalid data'}), 400
    
    user = {'id': random.randint(1000, 9999), 'name': data['name']}
    
    business_transactions.labels(transaction_type='user_creation', status='success').inc()
    
    return jsonify(user), 201


@app.route('/api/transaction', methods=['POST'])
@track_metrics
def create_transaction():
    time.sleep(random.uniform(0.1, 0.3))
    
    data = request.get_json()
    
    if not data or 'amount' not in data or 'currency' not in data:
        error_count.labels(error_type='ValidationError').inc()
        business_transactions.labels(transaction_type='payment', status='failed').inc()
        return jsonify({'error': 'Invalid transaction data'}), 400
    
    amount = float(data['amount'])
    currency = data['currency']
    
    if amount <= 0:
        error_count.labels(error_type='InvalidAmount').inc()
        business_transactions.labels(transaction_type='payment', status='failed').inc()
        return jsonify({'error': 'Amount must be positive'}), 400
    
    business_revenue.labels(currency=currency).inc(amount)
    business_transactions.labels(transaction_type='payment', status='success').inc()
    
    transaction = {
        'id': random.randint(10000, 99999),
        'amount': amount,
        'currency': currency,
        'status': 'completed'
    }
    
    return jsonify(transaction), 201


