@app.route('/api/random')
@track_metrics
def random_endpoint():
    time.sleep(random.uniform(0.01, 0.5))
    
    status_code = random.choice([200, 200, 200, 400, 500])
    
    if status_code == 400:
        error_count.labels(error_type='BadRequest').inc()
        return jsonify({'error': 'Bad request'}), 400
    elif status_code == 500:
        error_count.labels(error_type='InternalError').inc()
        return jsonify({'error': 'Internal error'}), 500
    
    return jsonify({'message': 'Success', 'random_value': random.randint(1, 100)}), 200


@app.before_request
def before_request():
    request.start_time = time.time()


@app.after_request
def after_request(response):
    if hasattr(request, 'start_time'):
        duration = time.time() - request.start_time
        
        if response.content_length:
            endpoint = request.endpoint or 'unknown'
            response_size.labels(endpoint=endpoint).observe(response.content_length)
    
    return response


